#!/usr/bin/env python3
"""Assert the deterministic results generated by ``prototype.py``.

The script is intentionally independent of the checker implementation: it reads
``evaluation_results.csv`` and fails when scenario counts, status distribution,
or direct impact outcomes differ from the paper's evaluated contract.
"""

from __future__ import annotations

import csv
import sys
from collections import Counter
from pathlib import Path

EXPECTED_STATUS_COUNTS = {
    "accepted": 2,
    "accepted_with_reservations": 1,
    "conditional": 2,
    "pending_review": 3,
    "rejected": 9,
    "not_derived": 1,
}
EXPECTED_SCENARIOS = sum(EXPECTED_STATUS_COUNTS.values())
EXPECTED_IMPACT_QUERIES = 4


def main() -> int:
    repo_root = Path(__file__).resolve().parents[1]
    csv_path = repo_root / "evaluation_results.csv"
    if not csv_path.exists():
        print(f"ERROR: missing generated result file: {csv_path}")
        return 2

    with csv_path.open(newline="", encoding="utf-8") as stream:
        rows = list(csv.DictReader(stream))

    scenarios = [row for row in rows if row.get("kind") == "scenario"]
    impacts = [row for row in rows if row.get("kind") == "impact_query"]

    errors: list[str] = []

    if len(scenarios) != EXPECTED_SCENARIOS:
        errors.append(
            f"expected {EXPECTED_SCENARIOS} scenarios, found {len(scenarios)}"
        )
    if len(impacts) != EXPECTED_IMPACT_QUERIES:
        errors.append(
            f"expected {EXPECTED_IMPACT_QUERIES} impact queries, found {len(impacts)}"
        )

    failed_rows = [
        row for row in rows if str(row.get("pass", "")).strip().lower() != "true"
    ]
    if failed_rows:
        errors.append(
            "failed rows: " + ", ".join(row.get("name", "<unnamed>") for row in failed_rows)
        )

    observed_counts = Counter(row.get("observed") for row in scenarios)
    if dict(observed_counts) != EXPECTED_STATUS_COUNTS:
        errors.append(
            "unexpected status distribution: "
            f"expected {EXPECTED_STATUS_COUNTS}, observed {dict(observed_counts)}"
        )

    impact_expectations = {
        "change::C002_FDA": "hit",
        "change::D001_Medication": "hit",
        "change::U001_DrugDBFrequency": "hit",
        "change::G005": "miss",
    }
    observed_impacts = {row.get("name"): row.get("observed") for row in impacts}
    if observed_impacts != impact_expectations:
        errors.append(
            "unexpected impact results: "
            f"expected {impact_expectations}, observed {observed_impacts}"
        )

    if errors:
        print("DERIVATION RESULT ASSERTION FAILED")
        for error in errors:
            print(f"- {error}")
        return 1

    print(f"Scenario result assertion: {len(scenarios)}/{EXPECTED_SCENARIOS} passed")
    print(f"Status distribution: {EXPECTED_STATUS_COUNTS}")
    print(f"Impact result assertion: {len(impacts)}/{EXPECTED_IMPACT_QUERIES} passed")
    return 0


if __name__ == "__main__":
    sys.exit(main())
